parameters.jsCode:
const client = $('Por cliente').item.json;
const content = $('Contenido 7d').item.json || [];
const leads = $('Leads 7d').item.json || [];

const contentByPlatform = {};
content.forEach(c => {
  contentByPlatform[c.platform] = (contentByPlatform[c.platform] || 0) + 1;
});

const hotLeads = leads.filter(l => (l.score || 0) >= 4).length;
const qualified = leads.filter(l => l.status === 'qualified').length;

return [{
  json: {
    client_id: client.id,
    client_name: client.business_name,
    contact_email: client.contact_email,
    contact_name: client.contact_name || 'equipo',
    plan: client.plan,
    summary: {
      content_published: content.filter(c => c.status === 'published').length,
      content_pending: content.filter(c => c.status === 'pending_review').length,
      by_platform: contentByPlatform,
      new_leads: leads.length,
      hot_leads: hotLeads,
      qualified_leads: qualified,
      sources: [...new Set(leads.map(l => l.source).filter(Boolean))],
    }
  }
}];

